import React from 'react';

const SettingsPage = () => {
  return (
    <div className="p-6 font-body">
      <h1 className="text-2xl font-display font-bold text-white mb-2">Settings</h1>
      <p className="text-slate-400">Manage your profile and platform preferences.</p>

      <div className="mt-8 bg-surface-800 border border-surface-600 rounded-xl p-6 flex flex-col items-center justify-center text-center h-64">
        <div className="text-4xl mb-4">⚙️</div>
        <h3 className="text-white font-medium mb-2">Preferences</h3>
        <p className="text-slate-500 text-sm max-w-sm">Advisor configuration and profile settings.</p>
      </div>
    </div>
  );
};

export default SettingsPage;
